// // This is a 32-bit down-counter that decrements from 2^32 - 1 to 0.
module counter_32bit (  
    input clk,  
    input reset,  
    input enable,  
    output reg [31:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 32'd0;  
        end else if (enable) begin  
            count <= count + 1;  
        end  
    end  
endmodule
